$apps = @('Microsoft.MicrosoftSolitaireCollection', 'Microsoft.BingNews', 'Microsoft.BingWeather', 'Microsoft.BingSports', 'Microsoft.BingFinance', 'Microsoft.WindowsFeedbackHub', 'Microsoft.GetHelp', 'Microsoft.Getstarted', 'Microsoft.MicrosoftOfficeHub', 'Microsoft.People', 'Microsoft.SkypeApp', 'Microsoft.WindowsMaps', 'Microsoft.3DViewer', 'Microsoft.MixedReality.Portal', 'Microsoft.OneConnect', 'Microsoft.Office.OneNote'); foreach ($app in $apps) { Write-Host "Salinama: $app..." -NoNewline; $p = Get-AppxPackage $app; if ($p) { try { $p | Remove-AppxPackage -ErrorAction Stop; Write-Host ' [OK]' -ForegroundColor Green } catch { Write-Host ' [KLAIDA]' -ForegroundColor Red } } else { Write-Host ' [NERASTA]' -ForegroundColor Gray } }
